// package-lock-manager.js

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

function generatePackageLock() {
    const packageJsonPath = path.resolve(process.cwd(), 'package.json');

    if (!fs.existsSync(packageJsonPath)) {
        console.error('package.json not found in the current directory.');
        return;
    }

    try {
        console.log('Generating package-lock.json...');
        execSync('npm install --package-lock-only', { stdio: 'inherit' });
        console.log('package-lock.json generation successful.');
    } catch (error) {
        console.error('Error generating package-lock.json:', error.message);
    }
}

function updatePackageLock() {
    try {
        console.log('Updating package-lock.json...');
        execSync('npm install', { stdio: 'inherit' });
        console.log('package-lock.json update successful.');
    } catch (error) {
        console.error('Error updating package-lock.json:', error.message);
    }
}

function managePackageLock(command) {
    switch (command) {
        case 'generate':
            generatePackageLock();
            break;
        case 'update':
            updatePackageLock();
            break;
        default:
            console.error('Unknown command. Use "generate" or "update".');
    }
}

// Usage: node package-lock-manager.js generate|update
const command = process.argv[2];
managePackageLock(command);